const globalStore = $getWorkflowStaticData('global');
const STALE_MS = 45 * 60 * 1000;
const lock = globalStore._enriching;
if (lock && (Date.now() - lock.startedAt) < STALE_MS) {
  return [{ json: { already_running: true, total: 0, leads: [] } }];
}

const raw = $input.first().json;
const [headers, ...rows] = raw.values || [[]];
const onlyMissing = $('Webhook').first().json.body?.only_missing !== false;
const leads = rows
  .map((row, i) => ({
    ...Object.fromEntries(headers.map((h, j) => [h, row[j] || ''])),
    _rowNumber: i + 2
  }))
  .filter(lead => !onlyMissing || !lead.person_name || lead.person_name === '');

if (leads.length === 0) {
  return [{ json: { already_running: false, total: 0, leads: [] } }];
}

globalStore._enriching = { executionId: $execution.id, startedAt: Date.now() };
return [{ json: { already_running: false, total: leads.length, leads } }];

const execId = $execution.id;
const store = $getWorkflowStaticData('global');
delete store[execId];
delete store._enriching;
return [];

const execId = $execution.id;
const store = $getWorkflowStaticData('global');
if (!store[execId]) store[execId] = {};
const lead = $input.first().json;
store[execId].pendingLead = { _rowNumber: lead._rowNumber };
store[execId].leadInfo = { name: lead.name || '', address: lead.address || '', phone: lead.phone || '', website: lead.website || '' };
const location = (lead.address || '').split(',').slice(-2).join(',').trim();
const websitePart = lead.website ? ' ' + lead.website.replace(/^https?:\/\//, '').replace(/\/$/, '') : '';
const query = (lead.name || '') + ' ' + location + websitePart + ' owner CEO director email LinkedIn';
return [{ json: { tavily_body: { api_key: $env.TAVILY_API_KEY, query: query.trim(), search_depth: 'advanced', max_results: 5, include_answer: true, include_raw_content: false } }}];

const execId = $execution.id;
const store = $getWorkflowStaticData('global');
const leadInfo = store[execId]?.leadInfo || {};
store[execId].broadResults = $input.first().json;
let secondQuery;
if (leadInfo.website) {
  const domain = leadInfo.website.replace(/^https?:\/\//, '').replace(/\/.*$/, '');
  secondQuery = 'site:' + domain + ' owner contact about team';
} else {
  const location = (leadInfo.address || '').split(',').slice(-2).join(',').trim();
  secondQuery = '"' + (leadInfo.name || '') + '" ' + location + ' owner founder director site:linkedin.com OR site:facebook.com';
}
return [{ json: { tavily_site_body: { api_key: $env.TAVILY_API_KEY, query: secondQuery.trim(), search_depth: 'advanced', max_results: 5, include_answer: true, include_raw_content: false }}}];

const execId = $execution.id;
const store = $getWorkflowStaticData('global');
const leadInfo = store[execId]?.leadInfo || {};
const broadResult = store[execId]?.broadResults || {};
const siteResult = $input.first().json;
function extractContext(result) {
  const answer = result.answer || '';
  const results = (result.results || []).slice(0, 5).map(r => r.title + '
' + r.url + '
' + (r.content || '')).join('
---
');
  return [answer, results].filter(Boolean).join('

');
}
const broadContext = extractContext(broadResult);
const siteContext = extractContext(siteResult);
const contextBlock = [broadContext, siteContext ? '=== Targeted Search ===
' + siteContext : ''].filter(Boolean).join('

');
const prompt = 'Business name: ' + (leadInfo.name || 'N/A') + '
Address: ' + (leadInfo.address || 'N/A') + '
Phone: ' + (leadInfo.phone || 'N/A') + '
Website: ' + (leadInfo.website || 'N/A') + '

Web search results:
' + (contextBlock || 'No results') + '

You are an expert researcher. Using ONLY the search results above, extract the decision maker (owner, CEO, Director) for this business. Do NOT guess. Return N/A for any field not clearly supported by the results.

Respond ONLY in this exact format:
PERSON_NAME: [full name or N/A]
PERSON_TITLE: [job title or N/A]
PERSON_EMAIL: [email or N/A]
PERSON_LINKEDIN: [URL or N/A]
PERSON_INSTAGRAM: [URL or N/A]
PERSON_TWITTER: [URL or N/A]';
return [{ json: { llm_body: { model: 'llama-3.3-70b-versatile', max_tokens: 512, temperature: 0.1, messages: [{ role: 'user', content: prompt }] }}}];

const execId = $execution.id;
const store = $getWorkflowStaticData('global');
const pendingLead = store[execId]?.pendingLead || {};
if (store[execId]) delete store[execId].pendingLead;

const response = $input.first().json;
const choices = response?.choices;
const text = choices?.[0]?.message?.content?.trim() || '';

if (response?.error || !choices || !Array.isArray(choices) || choices.length === 0 || !text) {
  return [{ json: { ...pendingLead, _should_update: false } }];
}

function extract(label) {
  const m = text.match(new RegExp(label + ':\\s*(.+)', 'i'));
  if (!m) return 'N/A';
  const v = m[1].trim();
  return /^n\/a$/i.test(v) || !v ? 'N/A' : v.substring(0, 500);
}

return [{ json: {
  ...pendingLead,
  person_name:      extract('PERSON_NAME'),
  person_title:     extract('PERSON_TITLE'),
  person_email:     extract('PERSON_EMAIL'),
  person_linkedin:  extract('PERSON_LINKEDIN'),
  person_instagram: extract('PERSON_INSTAGRAM'),
  person_twitter:   extract('PERSON_TWITTER'),
  _should_update: true
}}];
